INSERT INTO `v1_5c4970f021bc281eb1f8c5b9499b2ad4e485977d0de5bf739fbe0908c15bb96c` VALUES (10011004, "バトル開始時、すべてのモンスターの魔法防御力を特大アップさせる。この効果は魔法防御力ダウンの影響を受けない。", "boss_magic_def_lower_limit", "魔法防御力（ダウン不可）アップ", 4100110);
INSERT INTO `v1_5c4970f021bc281eb1f8c5b9499b2ad4e485977d0de5bf739fbe0908c15bb96c` VALUES (10011005, "バトル開始時、すべてのモンスターがＴＰダウン\n50％カット状態になる。", "boss_tp_down_cut", "ＴＰダウンカット", 4100110);
INSERT INTO `v1_5c4970f021bc281eb1f8c5b9499b2ad4e485977d0de5bf739fbe0908c15bb96c` VALUES (10011006, "バトル開始時、すべてのキャラのＴＰ上昇を中ダウンさせる。", 3, "ＴＰ上昇ダウン", 4100110);
INSERT INTO `v1_5c4970f021bc281eb1f8c5b9499b2ad4e485977d0de5bf739fbe0908c15bb96c` VALUES (10011007, "バトル開始時、すべてのキャラのＨＰ吸収を特大ダウンさせる。", 9, "ＨＰ吸収ダウン", 4100110);
